-- Reproduction for the IDENTITY-column + insert-check post-mutation evaluation
-- requirement.
--
-- Mirrors the exercise_log_sets fixture (composite-FK + defaulted discriminator)
-- but with `id` as a GENERATED BY DEFAULT AS IDENTITY column referenced by the
-- insert check. Identity columns surface via pg_attribute.attidentity rather
-- than pg_attrdef, so IsGenerated and HasDefault would both be false without
-- the IsIdentity bit; the pre-mutation check would then build its data CTE
-- with NULL standing in for `id` and the predicate (id > 0) would deny a
-- mutation that is actually valid post-INSERT.
--
-- The owner_id session-variable check anchors the per-tenant deny path: a
-- mismatched x-hasura-user-id still rejects the row even though the identity
-- column itself is valid.

CREATE TABLE public.identity_check_logs (
  id        bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  owner_id  uuid NOT NULL,
  note      text
);
